import time

def robust_step(fn, verify, *, max_retries=3, base_delay=0.5):
    """Execute a step with verification, idempotent retries, and escalation."""
    last_error = None
    for attempt in range(max_retries):
        try:
            result = fn()
            ok, reason = verify(result)          # spec check, not just no-exception
            if ok:
                return {"status": "ok", "result": result}
            last_error = f"verification failed: {reason}"
        except TransientError as e:              # network, rate limit, timeout
            last_error = str(e)
            time.sleep(base_delay * (2 ** attempt))   # exponential backoff
        except FatalError as e:                  # bad request, auth -> do not retry
            return {"status": "fatal", "error": str(e)}
    return {"status": "escalate", "error": last_error}   # hand to a human

def run_task(steps, on_escalate):
    """Run a multi-step task; a single unrecoverable step escalates instead of crashing."""
    state = {}
    for i, (fn, verify) in enumerate(steps):
        outcome = robust_step(lambda: fn(state), verify)
        if outcome["status"] == "ok":
            state[f"step_{i}"] = outcome["result"]
        else:
            return on_escalate(i, outcome, state)   # graceful degradation
    return {"status": "complete", "state": state}

class CircuitBreaker:
    """Trip after consecutive failures so a degraded agent stops instead of thrashing."""
    def __init__(self, threshold=5):
        self.threshold = threshold
        self.failures = 0
        self.open = False

    def record(self, ok: bool):
        if ok:
            self.failures = 0
        else:
            self.failures += 1
            if self.failures >= self.threshold:
                self.open = True          # halt further attempts

    def allow(self) -> bool:
        return not self.open

def run_with_budget(steps, breaker, max_cost, cost_of):
    spent = 0.0
    for step in steps:
        if not breaker.allow():
            return {"status": "halted", "reason": "circuit_open"}
        if spent + cost_of(step) > max_cost:
            return {"status": "halted", "reason": "budget_exceeded"}
        ok = step.run()
        breaker.record(ok)
        spent += cost_of(step)
    return {"status": "complete", "spent": spent}
